const results = [];
for (const item of $input.all()) {
  const binary = item.binary || {};
  const emailData = item.json;
  let fromText = '';
  if (emailData.from) {
    if (typeof emailData.from === 'string') fromText = emailData.from;
    else if (emailData.from.text) fromText = emailData.from.text;
    else if (emailData.from.value && emailData.from.value[0]) fromText = emailData.from.value[0].address || '';
  }
  const emailMeta = {
    emailSubject: emailData.subject || '',
    emailFrom: fromText,
    emailDate: emailData.date || '',
    emailMessageId: emailData.messageId || String(emailData.uid || Date.now())
  };
  for (const [key, binaryData] of Object.entries(binary)) {
    const filename = binaryData.fileName || binaryData.fileNameFull || key;
    const extension = filename.includes('.') ? filename.split('.').pop().toLowerCase() : '';
    results.push({
      json: { ...emailMeta, filename, extension, mimeType: binaryData.mimeType || '', fromZip: false },
      binary: { data: binaryData }
    });
  }
}
return results;

const results = [];
for (const item of $input.all()) {
  const binary = item.binary || {};
  const meta = item.json;
  for (const [key, binaryData] of Object.entries(binary)) {
    const filename = binaryData.fileName || binaryData.fileNameFull || key;
    if (filename.toLowerCase().endsWith('.zip')) continue;
    const extension = filename.includes('.') ? filename.split('.').pop().toLowerCase() : '';
    results.push({
      json: { emailSubject: meta.emailSubject || '', emailFrom: meta.emailFrom || '', emailDate: meta.emailDate || '', emailMessageId: meta.emailMessageId || '', filename, extension, mimeType: binaryData.mimeType || '', fromZip: true },
      binary: { data: binaryData }
    });
  }
}
return results;

const allItems = $input.all();

function stripCdata(text) {
  if (!text) return '';
  const s = text.trim();
  if (s.startsWith('<![CDATA[') && s.endsWith(']]>')) return s.slice(9, -3);
  return s;
}

function decodeEntities(text) {
  return text.replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&amp;/g, '&').replace(/&quot;/g, '\u0022').replace(/&#39;/g, '\u0027');
}

function getTagValue(xml, tag) {
  const re = new RegExp('<(?:[\\w.-]+:)?' + tag + '(?:\\s[^>]*)?>([\\s\\S]*?)<\/(?:[\\w.-]+:)?' + tag + '>', 'i');
  const m = xml.match(re);
  if (m && m[1]) { const val = m[1].replace(/<[^>]+>/g, '').trim(); return val || 'N/A'; }
  return 'N/A';
}

function getFirstMatch(xml, tags) {
  for (const tag of tags) { const val = getTagValue(xml, tag); if (val !== 'N/A') return val; }
  return 'N/A';
}

function getBlockContent(xml, tag) {
  const re = new RegExp('<(?:[\\w.-]+:)?' + tag + '(?:\\s[^>]*)?>([\\s\\S]*?)<\/(?:[\\w.-]+:)?' + tag + '>', 'i');
  const m = xml.match(re);
  return m ? m[1] : '';
}

function parseFactura(xmlContent) {
  const esAttachedDocument = /<(?:[\w.-]+:)?AttachedDocument[\s>]/i.test(xmlContent);
  let nitEmisor = 'N/A', razonSocial = 'N/A', numeroFactura = 'N/A', fechaEmision = 'N/A', valorTotal = '0', descripcion = 'N/A';
  let xmlPrincipal = xmlContent;
  const tipoDoc = esAttachedDocument ? 'AttachedDocument' : 'Invoice';
  if (esAttachedDocument) {
    numeroFactura = getTagValue(xmlContent, 'ID');
    fechaEmision  = getTagValue(xmlContent, 'IssueDate');
    const senderBlock = getBlockContent(xmlContent, 'SenderParty');
    if (senderBlock) { nitEmisor = getFirstMatch(senderBlock, ['CompanyID', 'ID']); razonSocial = getFirstMatch(senderBlock, ['RegistrationName', 'Name']); }
    const descBlock = getBlockContent(xmlContent, 'Description');
    if (descBlock) { let embebido = stripCdata(descBlock); embebido = decodeEntities(embebido).trim(); if (embebido.startsWith('<')) xmlPrincipal = embebido; }
  }
  if (nitEmisor === 'N/A') { const sb = getBlockContent(xmlPrincipal, 'AccountingSupplierParty'); if (sb) { nitEmisor = getFirstMatch(sb, ['CompanyID', 'ID']); razonSocial = getFirstMatch(sb, ['RegistrationName', 'Name']); } }
  if (numeroFactura === 'N/A') numeroFactura = getTagValue(xmlPrincipal, 'ID');
  if (fechaEmision === 'N/A')  fechaEmision  = getTagValue(xmlPrincipal, 'IssueDate');
  const mb = getBlockContent(xmlPrincipal, 'LegalMonetaryTotal');
  if (mb) valorTotal = getFirstMatch(mb, ['PayableAmount', 'TaxInclusiveAmount', 'LineExtensionAmount']);
  if (valorTotal === 'N/A' || valorTotal === '0') valorTotal = getFirstMatch(xmlPrincipal, ['PayableAmount', 'TaxInclusiveAmount']);
  const fl = getBlockContent(xmlPrincipal, 'InvoiceLine');
  if (fl) { const ib = getBlockContent(fl, 'Item'); descripcion = getFirstMatch(ib || fl, ['Description', 'Name']); }
  return { nitEmisor, razonSocial, numeroFactura, fechaEmision, valorTotal, descripcion, tipoDocumento: tipoDoc };
}

const grupos = {};
for (const item of allItems) {
  const id = item.json.emailMessageId || ('sin_id_' + Date.now());
  if (!grupos[id]) grupos[id] = { xmlItems: [], pdfItems: [], meta: { emailSubject: item.json.emailSubject || '', emailFrom: item.json.emailFrom || '', emailDate: item.json.emailDate || '', emailMessageId: item.json.emailMessageId || id } };
  if (item.json.extension === 'xml') grupos[id].xmlItems.push(item);
  else if (item.json.extension === 'pdf') grupos[id].pdfItems.push(item);
}

const resultados = [];
for (const [msgId, grupo] of Object.entries(grupos)) {
  for (const xmlItem of grupo.xmlItems) {
    const binaryData = xmlItem.binary && xmlItem.binary.data;
    if (!binaryData || !binaryData.data) continue;
    const xmlContent = Buffer.from(binaryData.data, 'base64').toString('utf-8');
    const facturaData = parseFactura(xmlContent);
    const pdfItem = grupo.pdfItems.length > 0 ? grupo.pdfItems[0] : null;
    const outputItem = { json: { ...grupo.meta, ...facturaData, xmlFilename: xmlItem.json.filename, pdfFilename: pdfItem ? pdfItem.json.filename : 'Sin PDF' }, binary: { xml: binaryData } };
    if (pdfItem && pdfItem.binary && pdfItem.binary.data) outputItem.binary.pdf = pdfItem.binary.data;
    resultados.push(outputItem);
  }
  if (grupo.xmlItems.length === 0 && grupo.pdfItems.length > 0) {
    for (const pdfItem of grupo.pdfItems) {
      resultados.push({ json: { ...grupo.meta, nitEmisor: 'N/A', razonSocial: 'N/A', numeroFactura: 'SIN_XML', fechaEmision: 'N/A', valorTotal: '0', descripcion: 'Correo sin XML adjunto', tipoDocumento: 'Solo PDF', xmlFilename: 'Sin XML', pdfFilename: pdfItem.json.filename }, binary: { pdf: pdfItem.binary.data } });
    }
  }
}

if (resultados.length === 0) return [{ json: { mensaje: 'No se encontraron facturas para procesar', timestamp: new Date().toISOString() } }];
return resultados;

// Construir el payload para la API de OpenAI
const results = [];

for (const item of $input.all()) {
  const j = item.json;

  const systemPrompt = 'Eres un asistente especializado en facturacion electronica colombiana (DIAN). Recibes datos extraidos de un XML UBL 2.1 y debes validarlos, limpiarlos y devolverlos en JSON estructurado.

Reglas estrictas:
1. Devuelve UNICAMENTE un objeto JSON valido, sin texto adicional, sin markdown, sin ```json.
2. Si un campo es N/A o esta vacio, intenta inferirlo del contexto. Si no es posible, dejalo como cadena vacia.
3. El campo valor_total debe ser un numero (float). Si viene con puntos de miles como 1.500.000 conviertelo a 1500000. Si tiene coma decimal como 1500000,50 conviertelo a 1500000.50.
4. La fecha debe quedar en formato YYYY-MM-DD.
5. El numero de factura debe incluir el prefijo (ej: FE-1234, FV0001).
6. La razon social debe estar en mayusculas.

Estructura de salida exacta:
{
  "nit_emisor": "string",
  "razon_social": "string",
  "numero_factura": "string",
  "fecha_emision": "string",
  "valor_total": number,
  "descripcion": "string",
  "tipo_documento": "string",
  "correo_remitente": "string",
  "fecha_correo": "string",
  "nombre_xml": "string",
  "nombre_pdf": "string"
}';

  const userPrompt = '=== DATOS EXTRAIDOS DEL XML ===
NIT Emisor: ' + (j.nitEmisor || '') + '
Razon Social: ' + (j.razonSocial || '') + '
Numero Factura: ' + (j.numeroFactura || '') + '
Fecha Emision: ' + (j.fechaEmision || '') + '
Valor Total: ' + (j.valorTotal || '') + '
Descripcion: ' + (j.descripcion || '') + '
Tipo Documento: ' + (j.tipoDocumento || '') + '

=== DATOS DEL CORREO ===
Remitente: ' + (j.emailFrom || '') + '
Asunto: ' + (j.emailSubject || '') + '
Fecha Correo: ' + (j.emailDate || '') + '
Archivo XML: ' + (j.xmlFilename || '') + '
Archivo PDF: ' + (j.pdfFilename || '') + '

Valida, limpia y estructura estos datos segun las reglas indicadas.';

  results.push({
    json: {
      ...j,
      _openAIPayload: {
        model: 'gpt-4o',
        temperature: 0,
        messages: [
          { role: 'system', content: systemPrompt },
          { role: 'user',   content: userPrompt }
        ]
      }
    },
    binary: item.binary || {}
  });
}

return results;

// Parsear la respuesta de OpenAI y limpiar el JSON devuelto
const results = [];

for (const item of $input.all()) {
  // La respuesta HTTP de OpenAI viene en choices[0].message.content
  let rawContent = '';
  try {
    rawContent = item.json.choices[0].message.content || '';
  } catch(e) {
    rawContent = '';
  }

  // Limpiar posible markdown code block que el LLM pueda agregar
  rawContent = rawContent.trim();
  if (rawContent.startsWith('```')) {
    const firstNewline = rawContent.indexOf('\n');
    rawContent = rawContent.substring(firstNewline + 1);
    if (rawContent.endsWith('```')) rawContent = rawContent.slice(0, -3).trim();
  }

  let facturaLimpia = {};
  try {
    facturaLimpia = JSON.parse(rawContent);
  } catch (e) {
    facturaLimpia = {
      error_parseo: 'No se pudo parsear la respuesta de OpenAI',
      respuesta_raw: rawContent
    };
  }

  // Asegurar que valor_total sea numero
  if (facturaLimpia.valor_total !== undefined && typeof facturaLimpia.valor_total === 'string') {
    const numStr = facturaLimpia.valor_total.replace(/\./g, '').replace(',', '.');
    const num = parseFloat(numStr);
    facturaLimpia.valor_total = isNaN(num) ? 0 : num;
  }

  // Generar nombre de carpeta seguro para Google Drive
  const numFactura = (facturaLimpia.numero_factura || 'SIN_NUMERO').replace(/[^a-zA-Z0-9_-]/g, '_');
  const fechaHoy   = new Date().toISOString().slice(0, 10);
  facturaLimpia.carpeta_nombre = 'Factura_' + numFactura + '_' + fechaHoy;

  results.push({
    json: facturaLimpia,
    binary: $('Parsear XML UBL 2.1').item.binary || {}
  });
}

return results;

const driveResponse = $input.first().json;
const files = driveResponse.files || [];
const invoiceData = $('Procesar Respuesta OpenAI').item.json;
const carpeta_raiz_id = files.length > 0 ? files[0].id : null;
return [{
  json: {
    ...invoiceData,
    carpeta_raiz_id: carpeta_raiz_id,
    _raiz_existe: carpeta_raiz_id !== null
  },
  binary: $('Procesar Respuesta OpenAI').item.binary || {}
}];

const newFolder = $input.first().json;
const invoiceData = $('Procesar Respuesta OpenAI').item.json;
return [{
