const driveResponse = $input.first().json;
const files = driveResponse.files || [];
let prevData;
try {
  const d = $('Fijar ID Carpeta Raiz Nueva').item.json;
  prevData = (d && d.carpeta_raiz_id) ? d : $('Extraer ID Carpeta Raiz').item.json;
} catch(e) {
  prevData = $('Extraer ID Carpeta Raiz').item.json;
}
const carpeta_archivos_id = files.length > 0 ? files[0].id : null;
return [{
  json: {
    ...prevData,
    carpeta_archivos_id: carpeta_archivos_id,
    _archivos_existe: carpeta_archivos_id !== null
  },
  binary: $('Procesar Respuesta OpenAI').item.binary || {}
}];

const newFolder = $input.first().json;
const prevData = $('Extraer ID Carpeta Archivos').item.json;
return [{
  json: {
    ...prevData,
    carpeta_archivos_id: newFolder.id,
    _archivos_existe: false
  },
  binary: $('Procesar Respuesta OpenAI').item.binary || {}
}];

const newFolder = $input.first().json;
const prevData = $('Extraer ID Carpeta Archivos').item.json;
return [{
  json: {
    ...prevData,
    carpeta_factura_id: newFolder.id,
    carpeta_factura_nombre: newFolder.name
  },
  binary: $('Procesar Respuesta OpenAI').item.binary || {}
}];

const results = [];
for (const item of $input.all()) {
  const binary = item.binary || {};
  const pdfBinary = binary.pdf || null;
  const pdfFilename = (pdfBinary && (pdfBinary.fileName || pdfBinary.fileNameFull))
    || item.json.pdfFilename || item.json.nombre_pdf || 'factura.pdf';
  results.push({
    json: { ...item.json, _tipo_archivo: 'pdf', _filename: pdfFilename, _pdf_available: pdfBinary !== null },
    binary: pdfBinary ? { data: pdfBinary } : {}
  });
}
return results;

const results = [];
for (const item of $input.all()) {
  const binary = item.binary || {};
  const xmlBinary = binary.xml || null;
  const xmlFilename = (xmlBinary && (xmlBinary.fileName || xmlBinary.fileNameFull))
    || item.json.xmlFilename || item.json.nombre_xml || 'factura.xml';
  results.push({
    json: { ...item.json, _tipo_archivo: 'xml', _filename: xmlFilename, _xml_available: xmlBinary !== null },
    binary: xmlBinary ? { data: xmlBinary } : {}
  });
}
return results;

const driveOut = $input.first().json;
const invoice = $('Preparar PDF para Subir').item.json;
const fileId = driveOut.id || '';
const webLink = driveOut.webViewLink || (fileId ? 'https://drive.google.com/file/d/' + fileId + '/view' : '');
return [{
  json: {
    ...invoice,
    link_pdf: webLink,
    drive_id_pdf: fileId
  }
}];

const driveOut = $input.first().json;
const invoice = $('Preparar XML para Subir').item.json;
const fileId = driveOut.id || '';
const webLink = driveOut.webViewLink || (fileId ? 'https://drive.google.com/file/d/' + fileId + '/view' : '');
return [{
  json: {
    ...invoice,
    link_xml: webLink,
    drive_id_xml: fileId
  }
}];

const items = $input.all();
let pdfItem = null, xmlItem = null;
for (const item of items) {
  if (item.json._tipo_archivo === 'pdf') pdfItem = item.json;
  else if (item.json._tipo_archivo === 'xml') xmlItem = item.json;
}
const base = pdfItem || xmlItem || {};
return [{
  json: {
    nit_emisor:          base.nit_emisor || '',
    razon_social:        base.razon_social || '',
    numero_factura:      base.numero_factura || '',
    fecha_emision:       base.fecha_emision || '',
    valor_total:         base.valor_total || 0,
    descripcion:         base.descripcion || '',
    tipo_documento:      base.tipo_documento || '',
    correo_remitente:    base.correo_remitente || '',
    fecha_correo:        base.fecha_correo || '',
    nombre_pdf:          base.nombre_pdf || '',
    nombre_xml:          base.nombre_xml || '',
    link_pdf:            (pdfItem && pdfItem.link_pdf) || '',
    link_xml:            (xmlItem && xmlItem.link_xml) || '',
    carpeta_drive:       base.carpeta_factura_nombre || '',
    fecha_procesamiento: new Date().toISOString().slice(0, 10)
  }
}];
